const raw = $input.first().json;
const content = raw.choices && raw.choices[0] && raw.choices[0].message && raw.choices[0].message.content;
if (!content) throw new Error('Réponse OpenAI vide: ' + JSON.stringify(raw).slice(0, 500));
let s = String(content).trim().replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/,'').trim();
let parsed;
try {
  parsed = JSON.parse(s);
} catch (e) {
  throw new Error('JSON invalide: ' + e.message + ' — ' + s.slice(0, 300));
}
const meta = $('9 - Assemble LLM payload').first().json;
const cvText = String($('8 - Get CV text (PCA, no OpenAI)').first().json.text || '');

function nsp(v) { return String(v || '').replace(/\s+/g, ' ').trim(); }
function norm(v) { return nsp(v).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, ''); }

function isNoiseCandName(n) {
  if (n == null || String(n).trim() === '') return true;
  const x = norm(n);
  if (/^(a propos de moi|about me|soft skills|hard skills|formation|projets?|competences|skills|resume|summary)$/.test(x)) return true;
  if (/\bpropos\b/.test(x) && /\bmoi\b/.test(x)) return true;
  if (/\babout\b/.test(x) && /\bme\b/.test(x)) return true;
  return false;
}

function isNoiseEmployerName(v) {
  const t = norm(v).replace(/[.,;:!?]+$/g, '');
  if (!t) return true;
  if (/^(present|actuel|actuelle|actuellement|current|maintenant|aujourd hui)$/.test(t)) return true;
  if (/^(project|projet|application|app|website|site web|portfolio|capstone|cloud engineer|devops engineer|data analyst|bi engineer)$/.test(t)) return true;
  return false;
}

function inferSchoolFromCv(cv, fallback) {
  const txt = String(cv || '');
  const lines = txt.split(/\r?\n/).map((l) => nsp(l)).filter(Boolean);
  const schoolRegex = /(emsi|ensias|inpt|ensam|ensa|enset|est|fst|faculte|facult[eé] des sciences|ofppt|supmti|uic|esca|isga|uir|universite)/i;
  for (const l of lines) {
    if (schoolRegex.test(l) && l.length >= 8) return l;
  }
  const inline = txt.match(/(EMSI[^\n]{0,120}|ENSIAS[^\n]{0,120}|INPT[^\n]{0,120}|ENSET[^\n]{0,120}|EST[^\n]{0,120}|FST[^\n]{0,120}|Facult[ée][^\n]{0,120}|Universit[ée][^\n]{0,120})/i);
  return inline ? nsp(inline[0]) : nsp(fallback || '');
}

function inferSchoolType(school, rawType) {
  const t = norm(rawType).toUpperCase();
  if (t === 'PUBLIC' || t === 'PRIVE') return t;
  const s = norm(school);
  if (!s) return null;
  if (/(emsi|supmti|uic|esca|isga|universiapolis|upm|hem|uir)/.test(s)) return 'PRIVE';
  if (/(ensias|inpt|ensam|ensa|enset|est|fst|\bfs\b|faculte|ofppt|universite hassan|universite mohammed|ibn tofail)/.test(s)) return 'PUBLIC';
  return null;
}

function parseRangeToMonths(startMonth, startYear, endMonth, endYear) {
  const s = Number(startYear) * 12 + Number(startMonth);
  const e = Number(endYear) * 12 + Number(endMonth);
  const d = e - s + 1;
  return d > 0 ? d : 0;
}

function extractExperienceMonths(cv) {
  const txt = norm(cv);
  const monthMap = { janv:1, janvier:1, fev:2, fevrier:2, mars:3, avr:4, avril:4, mai:5, juin:6, juil:7, juillet:7, aout:8, sept:9, septembre:9, oct:10, octobre:10, nov:11, novembre:11, dec:12, decembre:12 };
  const monthKeys = Object.keys(monthMap).join('|');
  const re = new RegExp(`\\b(${monthKeys})\\s+(20\\d{2})\\s*[-–]\\s*(${monthKeys}|present|actuel|actuelle|actuellement)\\s*(20\\d{2})?`, 'gi');
  let m;
  let total = 0;
  let count = 0;
  const now = new Date();
  while ((m = re.exec(txt)) !== null) {
    const sm = monthMap[m[1]];
    const sy = parseInt(m[2], 10);
    const endToken = m[3];
    const em = monthMap[endToken] || (endToken.startsWith('act') || endToken === 'present' ? now.getMonth() + 1 : null);
    const ey = m[4] ? parseInt(m[4], 10) : (endToken.startsWith('act') || endToken === 'present' ? now.getFullYear() : null);
    if (!sm || !sy || !em || !ey) continue;
    const d = parseRangeToMonths(sm, sy, em, ey);
    if (d > 0 && d <= 120) {
      total += d;
      count += 1;
    }
  }
  return { totalMonths: total || null, detectedCount: count || null };
}

function formatDuration(months) {
  if (!months || months <= 0) return '';
  if (months < 12) return `${months} mois`;
  const y = Math.floor(months / 12);
  const m = months % 12;
  if (!m) return `${y} an${y > 1 ? 's' : ''}`;
  return `${y} an${y > 1 ? 's' : ''} ${m} mois`;
}

function parseMonths(rawDur) {
  const sDur = norm(rawDur);
  if (!sDur) return null;
  let months = 0;
  const y = sDur.match(/(\d+(?:[.,]\d+)?)\s*(an|ans|year|years)/);
  const m = sDur.match(/(\d+(?:[.,]\d+)?)\s*(mois|month|months)/);
  if (y) months += Math.round(parseFloat(y[1].replace(',', '.')) * 12);
  if (m) months += Math.round(parseFloat(m[1].replace(',', '.')));
  if (!months) {
    const only = sDur.match(/^\d+(?:[.,]\d+)?$/);
    if (only) months = Math.round(parseFloat(only[0].replace(',', '.')) * 12);
  }
  return months > 0 ? months : null;
}

function lastEmployerFromCv(cv) {
  const txt = String(cv || '');
  const re = /([^\n|()]{3,80})\s*(?:\(|\|)/g;
  const arr = [];
  let m;
  while ((m = re.exec(txt)) !== null) {
    const company = nsp(m[1]);
    if (isNoiseEmployerName(company)) continue;
    const win = txt.slice(Math.max(0, m.index - 120), Math.min(txt.length, m.index + 280));
    const years = [...win.matchAll(/\b(19|20)\d{2}\b/g)].map(mm => parseInt(mm[0], 10));
    const maxYear = years.length ? Math.max(...years) : -1;
    arr.push({ company, maxYear, pos: m.index });
  }
  if (!arr.length) return null;
  arr.sort((a, b) => (b.maxYear - a.maxYear) || (a.pos - b.pos));
  return arr[0].company;
}

const rawName = parsed.candidate_name ?? parsed.candidateName ?? parsed.full_name ?? parsed.nom_candidat ?? parsed.nomComplet;
const candidateRaw = rawName != null && String(rawName).trim() !== '' ? String(rawName).trim() : null;
const candidate_name = candidateRaw && !isNoiseCandName(candidateRaw) ? candidateRaw : null;

const expMeta = extractExperienceMonths(cvText);
let expCount = Number.isFinite(Number(parsed.experience_count)) ? Math.max(0, parseInt(String(parsed.experience_count), 10)) : 0;
if ((expCount === 0 || expCount > 8) && expMeta.detectedCount) expCount = expMeta.detectedCount;

let score = Number.isFinite(Number(parsed.score)) ? Number(parsed.score) : 50;
const offerMatch = Number.isFinite(Number(meta.offerMatchScore)) ? Number(meta.offerMatchScore) : null;
if (offerMatch != null) {
  if (offerMatch < 8) score = Math.min(score, 58);
  else if (offerMatch < 18) score = Math.min(score, 70);
}
score = Math.round(Math.max(0, Math.min(100, score)));
if (expCount === 0 && score > 68) score = 68;

let decision = String(parsed.decision || '').toUpperCase().trim();
if (expCount === 0 && decision === 'ACCEPTEE' && score <= 70) decision = 'A REVOIR';
if (!['ACCEPTEE','REFUSEE','A REVOIR','NON_LISIBLE'].includes(decision)) decision = 'A REVOIR';

const fromCv = lastEmployerFromCv(cvText);
const llmLeRaw = parsed.last_employer != null ? nsp(parsed.last_employer) : '';
const llmLe = isNoiseEmployerName(llmLeRaw) ? '' : llmLeRaw;
const last_employer = expCount === 0 ? null : (fromCv || llmLe || null);

const school = inferSchoolFromCv(cvText, parsed.school);
const school_type = inferSchoolType(school, parsed.school_type);

let durationMonths = parseMonths(parsed.experience_duration);
if (!durationMonths && expMeta.totalMonths) durationMonths = expMeta.totalMonths;
let experience_duration = durationMonths ? formatDuration(durationMonths) : '';
let experience_years_avg = Number.isFinite(Number(parsed.experience_years_avg)) ? Number(parsed.experience_years_avg) : null;

if (expCount <= 0) {
  experience_duration = '';
  experience_years_avg = null;
} else {
  if (durationMonths) {
    const avg = Number((durationMonths / 12 / Math.max(1, expCount)).toFixed(2));
    if (experience_years_avg == null || experience_years_avg <= 0 || experience_years_avg > avg + 0.2 || experience_years_avg < 0.08) {
      experience_years_avg = avg;
    }
  } else if (experience_years_avg != null && experience_years_avg > 0) {
    durationMonths = Math.max(1, Math.round(experience_years_avg * 12 * expCount));
    experience_duration = formatDuration(durationMonths);
  } else {
    experience_years_avg = null;
    experience_duration = '';
  }
}

return [{ json: { ...parsed, score, decision, school, school_type, experience_count: expCount, experience_duration, experience_years_avg, candidatureId: meta.candidatureId, offerTitle: meta.offerTitle, offerDescription: meta.offerDescription, candidate_name, last_employer } }];

const cvRes = $input.first().json;
const offer = $('7 - Set Offer Context').first().json;
const init = $('1 - Initialize Candidate API').first().json;
const email = $('2 - Merge (Email + API response)').first().json;

let cvText = String(cvRes.text || '').trim();
if (!cvText || cvText.length < 20) {
  cvText = '[CV TEXTE COURT/BRUITE]\nLe texte extrait est court, mais il faut continuer l analyse normalement (ne pas forcer NON_LISIBLE).\nUtiliser les éléments réellement présents: en-tête CV, expériences, compétences, et contexte email/offre.';
}
const offerTitle = String(offer.offerTitle || '');
const offerDescription = String(offer.offerDescription || '');
const subject = String(email.subject || '');
const fromVal = email.from && email.from.value && email.from.value[0];
const fromLine = fromVal ? `${fromVal.name || ''} <${fromVal.address}>`.trim() : String(email.from || '');
const bodySnippet = String(email.text || email.textPlain || '').slice(0, 2500);

const internalMatch = typeof offer._offerMatchScore === 'number' && Number.isFinite(offer._offerMatchScore) ? offer._offerMatchScore : null;
const CATALOG_MIN = 18;
const offerFromCatalog = internalMatch != null && internalMatch >= CATALOG_MIN;
const matchLine = internalMatch != null ? ('\n[Métadonnée PCA — matching sujet → catalogue] Score interne n8n : ' + internalMatch + ' (seuil dans ce workflow : ' + CATALOG_MIN + '). ' + (offerFromCatalog ? 'Offre catalogue retenue : le score mesure surtout l adéquation CV ↔ OFFRE CIBLE (titre + contexte), sans contredire fortement le SUJET (OBJET).' : 'Pas de match catalogue ferme : le titre OFFRE CIBLE suit le SUJET — le score mesure surtout l adéquation CV ↔ OBJET ; OFFRE CIBLE rappelle le même intitulé.')) : '';

const llmUserMessage = `CONTEXTE EMAIL (message reçu):\nRéférence A — SUJET (OBJET du mail, intention candidat) : ${subject}\nDe: ${fromLine}\nNom API: ${init.candidateName || init.fullName || ''}\nEmail API: ${init.email || ''}\nExtrait corps:\n${bodySnippet}\n\nRéférence B — OFFRE CIBLE (titre + contexte) :\nTitre: ${offerTitle}\nContexte: ${offerDescription}${matchLine}\n\nTEXTE CV (décodé serveur PCA, tronqué) :\n${cvText.slice(0, 15000)}\n\nOBJECTIF: extraire fidèlement les informations de CV sans hallucination, puis scorer la candidature selon OBJET + OFFRE CIBLE.`;

const systemPrompt = `Tu es Senior AI Recruiter pour Payment Center for Africa. Mission: extraction CV fiable + scoring métier strict.
Tu dois renvoyer UNIQUEMENT un JSON valide (sans markdown) avec exactement ces clés:
summary, skills, experience, strengths, risks, score, decision, offer_context, school, school_type, phone, experience_count, experience_duration, experience_years_avg, last_employer, candidate_name

Règles NON-NÉGOCIABLES:
1) Zéro hallucination: si donnée non certaine, mets null/chaîne vide, n'invente jamais.
2) candidate_name: uniquement nom réel candidat depuis en-tête CV.
3) school: nom établissement le plus explicite depuis section formation (pas générique).
4) school_type: PUBLIC ou PRIVE uniquement; sinon null.
5) experience_count: compter uniquement expériences professionnelles réelles (stages/emplois entreprise), pas projets académiques.
6) experience_duration: durée totale professionnelle (format lisible, ex: 10 mois, 1 an 2 mois).
7) experience_years_avg: moyenne par expérience = durée_totale_en_années / experience_count.
8) last_employer: dernier organisme professionnel réel (jamais 'Actuel', 'Présent', ni titre de projet).
9) score: entier 0..100 obligatoire, basé STRICTEMENT sur adéquation CV avec Objet + Offre cible (pas score CV générique).
10) decision: cohérente avec score (ACCEPTEE/REFUSEE/A REVOIR/NON_LISIBLE).

Barème score obligatoire:
- Adéquation compétences techniques avec offre: /45
- Adéquation missions/projet métier avec offre: /35
- Niveau d'expérience utile pour l'offre: /20
Total = score.
Si mismatch fort Objet/Offre/CV: score <= 60.
Si fort alignement Objet + Offre cible + CV: score >= 75.

Sortie: JSON strict uniquement.`;

return [
  {
    json: {
      llmUserMessage,
      systemPrompt,
      candidatureId: init.id,
      offerTitle,
      offerDescription,
      offerMatchScore: internalMatch,
    },
  },
];

const data = $input.first().json;
const offers = Array.isArray(data.offers) ? data.offers : [];
const merge = $('2 - Merge (Email + API response)').first().json;
const subjectRaw = String(merge.subject || '').trim();

function norm(s) {
  return String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/^re:\s*|^fwd:\s*/gi, '')
    .replace(/[\u2010-\u2015\u2212]/g, '-')
    .replace(/[_\u2013\u2014\-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const STOP = new Set(['le', 'la', 'les', 'des', 'une', 'pour', 'avec', 'stage', 'pfe', 'offre', 'emploi', 'candidature', 'poste', 'job', 'd', 'de', 'du', 'et', 'ou', 'the', 'a', 'an']);

function tokens(s) {
  return norm(s).split(/[^a-z0-9\u00c0-\u024f]+/).filter((t) => t.length > 1 && !STOP.has(t));
}

const subjN = norm(subjectRaw);
const subjTokens = new Set(tokens(subjectRaw));

const GROUPS = [
  { keys: ['devops', 'docker', 'aws', 'kubernetes', 'argo', 'terraform', 'jenkins', 'gitlab'], weight: 58 },
  { keys: ['data', 'analyst', 'bi', 'power', 'etl'], weight: 52 },
  { keys: ['full', 'stack', 'react', 'javascript', 'angular', 'vue'], weight: 48 },
  { keys: ['java', 'spring', 'boot'], weight: 42 },
  { keys: ['cloud', 'azure'], weight: 36 },
];

function scoreOffer(offer) {
  const title = String(offer.title || '');
  const tN = norm(title);
  let score = 0;
  for (const g of GROUPS) {
    const subHit = g.keys.some((k) => subjN.includes(k));
    const titHit = g.keys.some((k) => tN.includes(k));
    if (subHit && titHit) score += g.weight;
    if (subHit && !titHit) score -= 24;
  }
  if (subjN && tN && tN.length > 24 && subjN.length > 24 && (subjN.includes(tN) || tN.includes(subjN))) score += 88;
  let overlap = 0;
  for (const t of tokens(title)) {
    if (subjTokens.has(t)) overlap++;
  }
  score += overlap * 8;
  return score;
}

let best = null;
let bestScore = -1e9;
for (const o of offers) {
  const sc = scoreOffer(o);
  if (sc > bestScore) {
    bestScore = sc;
    best = o;
  }
}

const MIN_SCORE = 18;
let offerTitle;
let offerDescription;

if (best && bestScore >= MIN_SCORE) {
  offerTitle = best.title;
  offerDescription = [best.company, best.location].filter(Boolean).join(' - ');
} else {
  offerTitle = subjectRaw.replace(/^re:\s*|^fwd:\s*/gi, '').trim() || 'Poste';
  offerDescription = '';
}

return [{ json: { offerTitle, offerDescription, subject: subjectRaw, _offerMatchScore: bestScore } }];

const items = $input.all();
const baseUrl = 'http://127.0.0.1:9000';

return items.map((item) => {
  const uploadUrl = String(item.json.uploadUrl || '').trim();
  let fullUploadUrl = baseUrl + (uploadUrl.startsWith('/') ? uploadUrl : '/' + uploadUrl);
  if (!fullUploadUrl.startsWith('http')) fullUploadUrl = baseUrl + '/' + (uploadUrl.replace(/^\//, '') || 'cvs');
  const bin = item.binary || {};
  const attKey = Object.keys(bin).find((k) => k.startsWith('attachment_'));
  if (attKey && attKey !== 'attachment_0') bin.attachment_0 = bin[attKey];
  return { json: { ...item.json, fullUploadUrl }, binary: bin };
});

// Ne garder que les emails qui ressemblent à une candidature (sujet ou pièce jointe CV)
const items = $input.all();
const subjectKeywords = /candidature|cv|application|postule|resume|curriculum|offre|emploi/i;

const filtered = items.filter((item) => {
  const subject = String(item.json.subject || '').toLowerCase();
  const bin = item.binary || {};
  const attKey = Object.keys(bin).find((k) => /^attachment_?\d*$/i.test(k) || k === 'data');
  const hasAttachment = attKey && bin[attKey];
  const fn = (attKey && bin[attKey].fileName) || '';
  const hasCvAttachment = hasAttachment && /\.(pdf|docx?)$/i.test(fn);
  return subjectKeywords.test(subject) || hasCvAttachment;
});

return filtered;
